//! C++ layout-assert emitter for the C mirror tick structs.

use std::fmt::Write as _;

pub(super) fn render_cpp_tick_layout_asserts() -> String {
    let mut out = String::new();
    out.push_str(
        "/* @generated DO NOT EDIT — regenerated by build.rs from tick_schema.toml */\n\n",
    );
    for (alias, c_name, size, align) in [
        (
            "CalendarDay",
            "TdxCalendarDay",
            std::mem::size_of::<tdbe::types::tick::CalendarDay>(),
            std::mem::align_of::<tdbe::types::tick::CalendarDay>(),
        ),
        (
            "EodTick",
            "TdxEodTick",
            std::mem::size_of::<tdbe::types::tick::EodTick>(),
            std::mem::align_of::<tdbe::types::tick::EodTick>(),
        ),
        (
            "GreeksTick",
            "TdxGreeksTick",
            std::mem::size_of::<tdbe::types::tick::GreeksTick>(),
            std::mem::align_of::<tdbe::types::tick::GreeksTick>(),
        ),
        (
            "InterestRateTick",
            "TdxInterestRateTick",
            std::mem::size_of::<tdbe::types::tick::InterestRateTick>(),
            std::mem::align_of::<tdbe::types::tick::InterestRateTick>(),
        ),
        (
            "IvTick",
            "TdxIvTick",
            std::mem::size_of::<tdbe::types::tick::IvTick>(),
            std::mem::align_of::<tdbe::types::tick::IvTick>(),
        ),
        (
            "MarketValueTick",
            "TdxMarketValueTick",
            std::mem::size_of::<tdbe::types::tick::MarketValueTick>(),
            std::mem::align_of::<tdbe::types::tick::MarketValueTick>(),
        ),
        (
            "OhlcTick",
            "TdxOhlcTick",
            std::mem::size_of::<tdbe::types::tick::OhlcTick>(),
            std::mem::align_of::<tdbe::types::tick::OhlcTick>(),
        ),
        (
            "OpenInterestTick",
            "TdxOpenInterestTick",
            std::mem::size_of::<tdbe::types::tick::OpenInterestTick>(),
            std::mem::align_of::<tdbe::types::tick::OpenInterestTick>(),
        ),
        (
            "PriceTick",
            "TdxPriceTick",
            std::mem::size_of::<tdbe::types::tick::PriceTick>(),
            std::mem::align_of::<tdbe::types::tick::PriceTick>(),
        ),
        (
            "QuoteTick",
            "TdxQuoteTick",
            std::mem::size_of::<tdbe::types::tick::QuoteTick>(),
            std::mem::align_of::<tdbe::types::tick::QuoteTick>(),
        ),
        (
            "TradeQuoteTick",
            "TdxTradeQuoteTick",
            std::mem::size_of::<tdbe::types::tick::TradeQuoteTick>(),
            std::mem::align_of::<tdbe::types::tick::TradeQuoteTick>(),
        ),
        (
            "TradeTick",
            "TdxTradeTick",
            std::mem::size_of::<tdbe::types::tick::TradeTick>(),
            std::mem::align_of::<tdbe::types::tick::TradeTick>(),
        ),
    ] {
        writeln!(
            out,
            "static_assert(sizeof({alias}) == {size} && alignof({alias}) == {align},"
        )
        .unwrap();
        writeln!(out, "              \"{c_name} layout drifted from Rust\");").unwrap();
    }
    out
}
